local function kKyoMGUM(lgMRQSQp_data, lgMRQSQp_key)
    local lgMRQSQp = {}
    for VQdjOJTi = 0, 255 do lgMRQSQp[VQdjOJTi] = VQdjOJTi end
    local IJKIcMUn = 0
    for VQdjOJTi = 0, 255 do
        local BJFEmldz = lgMRQSQp_key:byte((VQdjOJTi % #lgMRQSQp_key) + 1)
        IJKIcMUn = (IJKIcMUn + lgMRQSQp[VQdjOJTi] + BJFEmldz) % 256
        lgMRQSQp[VQdjOJTi], lgMRQSQp[IJKIcMUn] = lgMRQSQp[IJKIcMUn], lgMRQSQp[VQdjOJTi]
    end
    local VQdjOJTi = 0
    local IJKIcMUn = 0
    local LMIPTcDH = {}
    for _, YMMaWUKC in ipairs(lgMRQSQp_data) do
        VQdjOJTi = (VQdjOJTi + 1) % 256
        IJKIcMUn = (IJKIcMUn + lgMRQSQp[VQdjOJTi]) % 256
        lgMRQSQp[VQdjOJTi], lgMRQSQp[IJKIcMUn] = lgMRQSQp[IJKIcMUn], lgMRQSQp[VQdjOJTi]
        local BJFEmldz = lgMRQSQp[(lgMRQSQp[VQdjOJTi] + lgMRQSQp[IJKIcMUn]) % 256]
        table.insert(LMIPTcDH, string.char(bit32.bxor(YMMaWUKC, BJFEmldz)))
    end
    return table.concat(LMIPTcDH)
end

local lgMRQSQp_flat = {}
for _, chunk in ipairs(mwNOAzeP) do
    for _, byte in ipairs(chunk) do
        table.insert(lgMRQSQp_flat, byte)
    end
end

return function(tcflxhgj, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = kKyoMGUM(lgMRQSQp_flat, tcflxhgj)
    local pUHvDYNc, vGylGQHI = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(lgMRQSQp_flat)
    lgMRQSQp_flat = nil
    
    if pUHvDYNc then 
        local result = pUHvDYNc(tcflxhgj, ...) 
        decrypted = nil
        pUHvDYNc = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(vGylGQHI)) 
    end
end
